// ===============================
// 提取任务字段（兼容多种入参形态）+ 新增：达人特征/产品卖点/达人照片/产品图片
// ===============================

const inputData = $input.item.json || {};

function pickRecordRoot(x) {
  const item0 = x?.data?.items?.[0];
  if (item0 && (item0.fields || item0.record_id || item0.id)) return item0;
  const r1 = x?.body?.data?.record;
  if (r1 && (r1.fields || r1.record_id)) return r1;
  const r2 = x?.data?.record;
  if (r2 && (r2.fields || r2.record_id)) return r2;
  const r3 = x?.record;
  if (r3 && (r3.fields || r3.record_id)) return r3;
  if (x?.fields || x?.record_id) return x;
  return {};
}

const rec = pickRecordRoot(inputData);
const fields = rec.fields || {};

const getText = (v) => {
  if (v == null) return '';
  if (typeof v === 'string' || typeof v === 'number') return String(v);
  if (Array.isArray(v)) {
    const texts = v
      .map(x => (x?.text ?? x?.value ?? x?.link ?? x?.url ?? (typeof x === 'string' ? x : '')))
      .filter(Boolean);
    return texts.join('；');
  }
  return String(v.text ?? v.value ?? v.link ?? v.url ?? '');
};

const getNumber = (v, def = 0) => {
  const s = getText(v).trim();
  if (!s) return def;
  const n = Number(s);
  return Number.isFinite(n) ? n : def;
};

const getFileTokens = (v) => {
  if (!Array.isArray(v)) return [];
  return v
    .map(f => ({
      file_token: f.file_token || f.fileToken || f.token || f.id || '',
      name: f.name || '',
      url: f.url || '',
      tmp_url: f.tmp_url || '',
      mimeType: f.type || f.mimeType || '',
      size: f.size || 0,
    }))
    .filter(x => x.file_token);
};

const script_name = getText(fields['脚本名称']);
const break_no = getText(fields['拆解编号']);
const status = getText(fields['状态']);
const shot_limit_s = getNumber(fields['单镜头上限(s)'], 15);

// 兼容：你有时用“爆款视频”，有时用“参考爆款视频”
const videoFiles = getFileTokens(fields['爆款视频'] || fields['参考爆款视频']);
const mainVideo = videoFiles[0] || {};
const video_file_token = mainVideo.file_token || '';
const video_file_name = mainVideo.name || '';
const video_url = mainVideo.url || '';
const video_tmp_url_api = mainVideo.tmp_url || '';

// 新增：达人/产品信息（字段名按你截图：达人特征、产品卖点、达人照片、产品图片）
const talent_traits = getText(fields['达人特征']);
const product_selling_points = getText(fields['产品卖点']);
const product_name = getText(fields['产品名称']);

const talentPhotos = getFileTokens(fields['达人照片']);
const productImages = getFileTokens(fields['产品图片']);
const talent_photo_token = talentPhotos[0]?.file_token || '';
const product_image_token = productImages[0]?.file_token || '';

const rec_api_key = getText(fields['api_key']);
const rec_app_id = getText(fields['app_id']);
const rec_app_secret = getText(fields['app_secret']);

const record_id =
  rec.record_id ||
  rec.id ||
  getText(fields['record_id']) ||
  inputData?.body?.record_id ||
  inputData?.record_id ||
  (() => { try { return $('Webhook').item.json.body?.record_id } catch (e) { return '' } })() ||
  'unknown_record';

const try_access_token = (() => {
  try {
    const j = $('Auth:getAccessToken auth1').first().json || {};
    return j.tenant_access_token || j.app_access_token || j.access_token || '';
  } catch (e) {
    return '';
  }
})();

const try_task_app_token = (() => { try { return $('获取任务表信息').first().json.app_token } catch(e){ return '' } })();
const try_task_table_id  = (() => { try { return $('获取任务表信息').first().json.table_id } catch(e){ return '' } })();
const try_break_app_token = (() => { try { return $('获取拆解表信息').first().json.app_token } catch(e){ return '' } })();
const try_break_table_id  = (() => { try { return $('获取拆解表信息').first().json.table_id } catch(e){ return '' } })();

return [{
  json: {
    script_name,
    break_no,
    status,
    shot_limit_s,

    // 视频
    video_file_token,
    video_file_name,
    video_url,
    video_tmp_url_api,

    // 任务主键
    record_id,

    // 新增：目标达人/产品信息
    product_name,
    talent_traits,
    product_selling_points,
    talent_photo_token,
    product_image_token,

    // 凭证
    api_key: rec_api_key || (() => { try { return $('Webhook').item.json.body?.api_key } catch(e){ return '' } })(),
    app_id: rec_app_id || (() => { try { return $('Webhook').item.json.body?.app_id } catch(e){ return '' } })(),
    app_secret: rec_app_secret || (() => { try { return $('Webhook').item.json.body?.app_secret } catch(e){ return '' } })(),
    try_get_access_token: try_access_token,

    // 表信息
    try_task_app_token,
    try_task_table_id,
    try_break_app_token,
    try_break_table_id,

    _raw_fields: fields,
  }
}];

// ===============================
// 整理分析提示词（Gemini generateContent）
// ✅ 直接用二进制视频 base64
// ✅ 固定 8s 分段拆解（最后一段允许 <8s 但必须输出）
// ✅ 强制输出段数 = ceil(video_duration/8)
// ✅ Agent 只输出必要字段：shot_no/subtitle_original/scene_context/video_prompt
// ✅ 严禁输出参考视频人物特征（避免后续生图吸走参考人外观）
// ✅ 强制“产品手位”一致（左/右手）
// ✅ 彻底禁止任何关键帧生图提示词字段（start_frame_prompt/end_frame_prompt 等）
// ===============================

function normalizeB64(s) {
  if (!s) return '';
  if (typeof s !== 'string') s = String(s);
  s = s.trim().replace(/^\\"+|\\"+$/g, '').trim();
  const m = s.match(/^data:([^;]+);base64,(.+)$/i);
  if (m && m[2]) return m[2].trim();
  return s.replace(/\s+/g, '');
}

const j = $json || {};
const task = $('提取任务字段').first().json || {};
const record_id = task.record_id || j.record_id || 'unknown_record';

// Extract from File 节点把 base64 放到了 json.video
const videoB64 = normalizeB64(j.video);
if (!videoB64) throw new Error('缺少视频 base64：请确认 Extract from File 输出 json.video');

const mimeType = 'video/mp4';

// ✅ 从“清洗json”拿压缩后的英文身份/产品（没有就兜底原始字段）
const idPack = (() => {
  try { return $('清洗json').first().json || {}; } catch(e) { return {}; }
})();
const model_identity_en = String(idPack.model_identity_en || '').trim();
const outfit_desc_en = String(idPack.outfit_desc_en || '').trim();

const talent_traits_raw = String(task.talent_traits || '').trim();
const product_name = String(task.product_name || '').trim();
const product_selling_points_raw = String(task.product_selling_points || '').trim();

const clip_duration_s = 8;
const video_path = `/tmp/${record_id}.mp4`;

// ✅ 取时长（来自 ffprobe -> 解析视频时长）
const durPack = (() => {
  try { return $('解析视频时长').first().json || {}; } catch (e) { return {}; }
})();
const video_duration_s = Number(durPack.video_duration_s || 0);
const expected_clips = (Number.isFinite(video_duration_s) && video_duration_s > 0)
  ? Math.ceil(video_duration_s / clip_duration_s)
  : null;

// ---------------- instruction：只产出必要字段（强制“去人物特征” + “手位一致” + “禁止关键帧提示词”） ----------------
const instruction = `
You are a video understanding agent.

You MUST split the entire timeline into consecutive clips of 8.00 seconds starting from 0s.
CRITICAL:
- Video duration is ${Number.isFinite(video_duration_s) ? video_duration_s.toFixed(3) : 'UNKNOWN'} seconds.
- You MUST output EXACTLY ${expected_clips ?? 'N'} items (shot_no 1..${expected_clips ?? 'N'}).
- shot_no=1 starts at 0s; shot_no=i starts at (i-1)*8.00 seconds.
- The LAST clip may be shorter than 8.00 seconds, but you MUST still output it.
- Do NOT drop the last partial clip.

Output ONLY a JSON array. No markdown. No extra text. No time_range.

Each item MUST be EXACTLY:
{
  "shot_no": 1,
  "subtitle_original": "Transcript ONLY for this clip (its own time span).",
  "scene_context": "ENGLISH, 60-170 chars. Describe ONLY: environment/background, camera/framing, pose/action (generic), lighting, mood, NON-human props + PRODUCT HAND (LEFT/RIGHT). ABSOLUTELY DO NOT describe any human appearance.",
  "video_prompt": "<A SINGLE JSON STRING following the schema below>"
}

ABSOLUTE BAN: DO NOT output ANY extra keys besides:
shot_no, subtitle_original, scene_context, video_prompt

CRITICAL: KEYFRAME/IMAGE PROMPT BAN
- Do NOT output: start_frame_prompt, end_frame_prompt, image_prompt, keyframe_prompt, prompt_start, prompt_end, negative_prompt_for_image
- Do NOT output any fields for generating images or keyframes. None.

STRICT HUMAN-APPEARANCE BAN (very important):
- Do NOT mention hair, face, eyes, lips, makeup, skin tone, ethnicity, age, gender.
- Do NOT mention clothing/outfit, jewelry, earrings, necklace, piercings, nails, tattoos, body shape.
- If you must refer to the subject, use ONLY: "the model" / "the person" / "the subject" (no descriptors).
- scene_context must be reusable with a DIFFERENT person inserted later.

PRODUCT HAND CONSISTENCY (critical):
- If the product is visible/handled/applied: include EXACT token in scene_context:
  "PRODUCT HAND: RIGHT HAND" OR "PRODUCT HAND: LEFT HAND"
- Determine the hand from the video. If ambiguous, default to "PRODUCT HAND: RIGHT HAND".
- IMPORTANT: Keep the SAME product hand across ALL clips. Use the first clear occurrence as the global choice.

video_prompt MUST be a JSON STRING (not an object) and MUST include:
- schema_version "1.0"
- scene_index (same as shot_no)
- audio_transcript (same as subtitle_original)
- dialogue (same as subtitle_original)
- beats (sum duration_seconds = 8 for full clips; for LAST partial clip, sum MUST equal its real clip length)
- camera, lighting, motion, constraints, negative
- process_description MUST include timeline and the same PRODUCT HAND choice
- video_settings.total_duration_seconds MUST equal the clip duration (8.00 for full clips; last partial duration for last clip)
- aspect_ratio 9:16, fps 25
`.trim();

// 给 Agent 的上下文：让它知道身份/产品，但严禁在输出里复述
const contextBlock = `
MODEL IDENTITY (for later prompt composition; DO NOT repeat or paraphrase in output):
${model_identity_en || talent_traits_raw || 'Not provided'}

OUTFIT / PRODUCT (for later prompt composition; DO NOT repeat or paraphrase in output):
${outfit_desc_en || `${product_name ? ('Name: ' + product_name + '\n') : ''}${product_selling_points_raw}` || 'Not provided'}

GLOBAL CONSTRAINTS:
- Photorealistic
- Vertical 9:16
- No on-screen text / watermark / UI / logos
- Output must NOT contain any human appearance details (hair/face/clothes/jewelry/makeup/skin tone).
- Output MUST lock PRODUCT HAND consistently across clips.
- Output MUST NOT contain any keyframe/image prompt fields.
`.trim();

const gemini_body = {
  contents: [
    {
      role: 'user',
      parts: [
        { text: `${instruction}\n\n${contextBlock}` },
        { inline_data: { mime_type: mimeType, data: videoB64 } }
      ]
    }
  ],
  generationConfig: {
    temperature: 0.1,
    topP: 0.9,
    maxOutputTokens: 8192
  }
};

return [{
  json: {
    record_id,
    clip_duration_s,
    video_path,
    video_duration_s: Number.isFinite(video_duration_s) ? Number(video_duration_s.toFixed(3)) : undefined,
    expected_clips,
    gemini_body
  }
}];

const results = [];
const sourceItems = $items('计算切片+截图路径（8s一体）');

for (const item of sourceItems) {
  const j = item.json || {};
  if (j.shot_no == null) throw new Error('缺少 shot_no（来自 计算切片+截图路径）');
  if (!j.frame_path_start || !j.frame_path_end) throw new Error(`缺少 frame_path_start/end：shot_no=${j.shot_no}`);

  results.push({
    json: {
      ...j,
      frame_path: j.frame_path_start,
      frame_type: 'start_frame',
    }
  });

  results.push({
    json: {
      ...j,
      frame_path: j.frame_path_end,
      frame_type: 'end_frame',
    }
  });
}

return results;

// ===============================
// 累积帧到缓存（修复 seen 可能不存在导致报错）
// ✅ 兼容旧缓存：只有 frames 没有 seen
// ✅ 用 record_id 隔离任务
// ✅ 去重：shot_no + frame_type + frame_path
// ===============================

// 兼容不同 n8n 环境的 staticData API
const store =
  (typeof $getWorkflowStaticData === 'function')
    ? $getWorkflowStaticData('node')
    : (typeof getWorkflowStaticData === 'function')
      ? getWorkflowStaticData('node')
      : null;

if (!store) {
  throw new Error("当前 Code 节点环境不支持 Workflow Static Data（找不到 $getWorkflowStaticData / getWorkflowStaticData）");
}

// record_id：优先当前输入，其次提取任务字段
const recordId =
  String(
    $input.first()?.json?.record_id ??
    $('提取任务字段')?.first()?.json?.record_id ??
    'unknown_record'
  );

// ✅ 关键：兼容旧结构（只要存在就补齐 seen）
if (!store[recordId] || typeof store[recordId] !== 'object') {
  store[recordId] = {};
}
if (!Array.isArray(store[recordId].frames)) {
  store[recordId].frames = [];
}
if (!store[recordId].seen || typeof store[recordId].seen !== 'object') {
  store[recordId].seen = {};
}

// 当前批次 items（分批上传 batch size=3）
const cur = $input.all().map(i => i.json || {});
if (!cur.length) {
  return [{
    json: {
      record_id: recordId,
      frames: store[recordId].frames,
      frames_count: store[recordId].frames.length,
      added: 0,
      skipped: 0
    }
  }];
}

let added = 0;
let skipped = 0;

for (const f of cur) {
  const shotNo = f.shot_no;
  const frameType = f.frame_type;
  const framePath = f.frame_path;

  if (shotNo == null || !frameType || !framePath) {
    // 这里不直接 throw，避免偶发字段缺失把整批卡死；你要更严格可以改成 throw
    skipped++;
    continue;
  }

  const k = `${shotNo}|${frameType}|${framePath}`;

  // ✅ 这里不会再读 undefined 了
  if (store[recordId].seen[k]) {
    skipped++;
    continue;
  }

  store[recordId].seen[k] = true;
  store[recordId].frames.push(f);
  added++;
}

return [{
  json: {
    record_id: recordId,
    frames: store[recordId].frames,
    frames_count: store[recordId].frames.length,
    added,
    skipped
  }
}];

const frames = Array.isArray($json.frames) ? $json.frames : [];
if (!frames.length) throw new Error('frames 为空：请确认“累积帧到缓存”有输出 frames[]');

const miss = frames.find(f => f.shot_no == null || !f.frame_type);
if (miss) {
  throw new Error(`frames 缺少 shot_no/frame_type：示例 keys=${Object.keys(miss).join(',')}`);
}

const byShot = new Map();

for (const f of frames) {
  const shotNo = Number(f.shot_no);
  if (!Number.isFinite(shotNo)) continue;

  if (!byShot.has(shotNo)) byShot.set(shotNo, { ...f });
  const t = byShot.get(shotNo);

  if (f.frame_type === 'start_frame') t.start_frame_file_token = f.frame_file_token;
  if (f.frame_type === 'end_frame')   t.end_frame_file_token   = f.frame_file_token;
}

// 强校验：每个镜头必须两张都有
const out = Array.from(byShot.values()).sort((a,b)=>a.shot_no-b.shot_no);

const bad = out.find(x => !x.start_frame_file_token || !x.end_frame_file_token);
if (bad) {
  throw new Error(`镜头缺首/尾帧 token：shot_no=${bad.shot_no}, start=${!!bad.start_frame_file_token}, end=${!!bad.end_frame_file_token}`);
}

return out.map(x => ({ json: x }));

// 上传返回（当前批次）
const uploadItems = $input.all();

// 关键：从“生成文件信息”取回这一批的原始 frame 元数据（这里才有 shot_no / frame_type）
const frameItems = $items('生成文件信息');

if (!uploadItems.length) return [];
if (!frameItems.length) {
  throw new Error('绑定失败：未拿到“生成文件信息”的 items（本批次帧元数据为空）');
}

if (uploadItems.length !== frameItems.length) {
  throw new Error(`绑定失败：上传数量(${uploadItems.length}) != 帧数量(${frameItems.length})，顺序无法按位置绑定`);
}

return uploadItems.map((upItem, idx) => {
  const up = upItem.json || {};
  const frame = frameItems[idx].json || {};

  const fileToken =
    up.body?.data?.file_token ||
    up.data?.file_token ||
    up.file_token ||
    '';

  if (!fileToken) {
    throw new Error(`上传结果缺少 file_token，idx=${idx}，keys=${Object.keys(up).join(',')}`);
  }

  // 输出必须保留 frame 的 shot_no / frame_type
  return {
    json: {
      ...frame,
      frame_file_token: fileToken,
    }
  };
});

const items = $input.all();
if (!items.length) return [];

const output = await Promise.all(items.map(async (item, index) => {
  const binary = item.binary || {};
  const keys = Object.keys(binary);
  if (!keys.length) throw new Error(`没有 Binary，index=${index}`);

  const key = keys.includes('data') ? 'data' : keys[0];
  const binData = binary[key];

  const buffer = await this.helpers.getBinaryDataBuffer(index, key);
  const realSize = buffer.length;

  const fileName =
    binData.fileName ||
    item.json.frame_path?.split('/').pop() ||
    `shot_${index}.jpg`;

  return {
    json: {
      ...item.json,
      fileName,
      fileSize: realSize,
      binaryKey: key,
    },
    binary: {
      [key]: {
        ...binData,
        fileName,
        fileSize: realSize
      }
    }
  };
}));

return output;

// ===============================
// 清洗结果（只保留 video_prompt）
// 输入：Gemini 返回 candidates[0].content.parts[].text 的 “JSON 数组”
// 输出：{ parsed_shots_count, shots[] }；shots 每项仅：shot_no/subtitle_original/scene_context/video_prompt
// ✅ 严禁输出关键帧生图提示词字段（start_frame_prompt/end_frame_prompt 等）
// ✅ video_prompt 强制为 JSON string，并补齐必要字段
// ✅ 强校验：shots 数量必须 == ceil(video_duration/8)，否则抛错触发 retry
// ===============================

const items = $input.all();

function toStr(v) {
  if (v == null) return '';
  if (typeof v === 'string') return v;
  try { return JSON.stringify(v); } catch (e) { return String(v); }
}

// 1) 从各种可能位置提取 Gemini 返回的 text
function pickText(allItems) {
  for (const it of allItems) {
    const j = it?.json ?? {};

    // 常见结构：j.candidates[0].content.parts[].text
    if (Array.isArray(j.candidates) && j.candidates.length) {
      const parts = j.candidates?.[0]?.content?.parts;
      if (Array.isArray(parts) && parts.length) {
        const t = parts.map(p => p?.text).filter(Boolean).join('\n').trim();
        if (t) return t;
      }
    }

    // 兼容：j.response.candidates[0].content.parts[].text
    const c = j?.response?.candidates?.[0];
    if (c?.content?.parts?.length) {
      const t = c.content.parts.map(p => p?.text).filter(Boolean).join('\n').trim();
      if (t) return t;
    }

    // 兼容：节点可能直接放 text/output
    if (typeof j.text === 'string' && j.text.trim()) return j.text.trim();
    if (typeof j.output === 'string' && j.output.trim()) return j.output.trim();
  }
  return '';
}

// 2) 清理 fenced json + 截取 JSON 主体
function extractJsonText(raw) {
  let t = toStr(raw).trim();
  if (!t) return '';

  t = t.replace(/\r\n/g, '\n').replace(/\r/g, '\n').trim();

  // 去掉 ```json / ``` fence（只处理首尾）
  t = t.replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();

  // 截取第一个 [ 或 { 到最后一个 ] 或 }
  const firstArr = t.indexOf('[');
  const firstObj = t.indexOf('{');
  let start = -1;
  if (firstArr >= 0 && firstObj >= 0) start = Math.min(firstArr, firstObj);
  else start = firstArr >= 0 ? firstArr : firstObj;

  const lastArr = t.lastIndexOf(']');
  const lastObj = t.lastIndexOf('}');
  let end = -1;
  if (lastArr >= 0 && lastObj >= 0) end = Math.max(lastArr, lastObj);
  else end = lastArr >= 0 ? lastArr : lastObj;

  if (start >= 0 && end > start) t = t.slice(start, end + 1).trim();

  // 智能引号兜底
  t = t.replace(/[“”]/g, '"').replace(/[‘’]/g, "'").replace(/\uFEFF/g, '');

  return t;
}

function safeParseJSON(s) {
  try { return JSON.parse(s); } catch (e) {
    // 常见尾逗号容错
    const s2 = s.replace(/,\s*([}\]])/g, '$1');
    return JSON.parse(s2);
  }
}

// 3) 关键帧/生图字段黑名单：任何地方出现都要删
const BANNED_KEYS = new Set([
  'start_frame_prompt', 'end_frame_prompt',
  'image_prompt', 'keyframe_prompt',
  'prompt_start', 'prompt_end',
  'negative_prompt_for_image',
  'start_frame', 'end_frame',
]);

function stripBannedKeysDeep(obj) {
  if (!obj || typeof obj !== 'object') return obj;
  if (Array.isArray(obj)) return obj.map(stripBannedKeysDeep);
  const out = {};
  for (const [k, v] of Object.entries(obj)) {
    if (BANNED_KEYS.has(k)) continue;
    out[k] = stripBannedKeysDeep(v);
  }
  return out;
}

// 4) beats 修正：补齐到指定时长（默认 8；最后一段可能更短）
function normalizeBeatsToTotal(beats, total) {
  if (!Array.isArray(beats) || !beats.length) return beats;

  const ds = beats.map(b => Number(b?.duration_seconds)).filter(x => Number.isFinite(x) && x > 0);
  if (ds.length !== beats.length) return beats;

  const sum = ds.reduce((a,b)=>a+b, 0);
  const diff = Number((total - sum).toFixed(3));

  // 容许 0.1 的误差，不动
  if (Math.abs(diff) <= 0.1) return beats;

  // 把差值加到最后一个 beat
  const last = beats[beats.length - 1];
  const lastD = Number(last.duration_seconds);
  if (Number.isFinite(lastD) && lastD > 0) {
    last.duration_seconds = Number((lastD + diff).toFixed(3));
    if (last.duration_seconds < 0.2) last.duration_seconds = 0.2; // 兜底避免负数
  }
  return beats;
}

// ========== 主流程 ==========
const raw = pickText(items);
if (!raw) throw new Error('未找到 Gemini 返回文本：请确认上游节点返回 candidates/content/parts/text');

const jsonText = extractJsonText(raw);
if (!jsonText) throw new Error('清洗后 JSON 文本为空：raw_head=' + raw.slice(0, 200));

let parsed;
try {
  parsed = safeParseJSON(jsonText);
} catch (e) {
  throw new Error(
    'JSON 解析失败（可能被截断或混入非JSON文本）\n' +
    'head:\n' + jsonText.slice(0, 260) + '\n' +
    'tail:\n' + jsonText.slice(Math.max(0, jsonText.length - 260))
  );
}

const arr = Array.isArray(parsed) ? parsed : (Array.isArray(parsed.shots) ? parsed.shots : []);
if (!arr.length) throw new Error('AI 返回 shots 为空或结构不对（期望 JSON 数组）');

// ✅ 强校验：shots 数量必须等于 ceil(video_duration/8)
const durPack = (() => { try { return $('解析视频时长').first().json || {}; } catch(e) { return {}; } })();
const video_duration_s = Number(durPack.video_duration_s || 0);
const CLIP = 8;

if (Number.isFinite(video_duration_s) && video_duration_s > 0) {
  const expected = Math.ceil(video_duration_s / CLIP);
  if (arr.length !== expected) {
    throw new Error(`分镜数量不对：expected=${expected}, got=${arr.length}, video_duration_s=${video_duration_s}`);
  }
}

// 计算每段真实时长：前面都是 8，最后一段是 video_duration_s - 8*(n-1)
function clipLenForShot(shotNo, totalShots, videoDur) {
  if (!Number.isFinite(videoDur) || videoDur <= 0) return 8;
  if (shotNo < totalShots) return 8;
  const last = videoDur - (totalShots - 1) * 8;
  return Math.max(0.2, Number(last.toFixed(3))); // 最小给 0.2s 防止极端
}

const totalShots = arr.length;

const shots = arr.map((x, idx) => {
  const shot_no = Number(x?.shot_no ?? (idx + 1)) || (idx + 1);
  const subtitle_original = String(x?.subtitle_original ?? '').trim();
  const scene_context = String(x?.scene_context ?? '').trim();

  // 只保留 4 字段（硬裁剪）
  let vp = x?.video_prompt;

  // 兼容：有些模型会把 video_prompt 给成对象
  if (vp && typeof vp === 'object') vp = JSON.stringify(vp);

  if (typeof vp !== 'string' || !vp.trim()) {
    throw new Error(`shot_no=${shot_no} 缺少 video_prompt（必须是 JSON string）`);
  }

  // video_prompt 内部必须是 JSON
  let vpObj;
  try {
    vpObj = safeParseJSON(vp);
  } catch (e) {
    throw new Error(`shot_no=${shot_no} 的 video_prompt 不是合法 JSON：head=${vp.slice(0, 160)}`);
  }

  // 深度清理：删掉 banned keys
  vpObj = stripBannedKeysDeep(vpObj);

  // 该段的真实时长：最后一段可能 < 8
  const thisDur = clipLenForShot(shot_no, totalShots, video_duration_s);

  // 补齐/修正必要字段
  vpObj.schema_version = vpObj.schema_version || '1.0';
  vpObj.scene_index = shot_no;
  vpObj.reference_priority = vpObj.reference_priority || 'keyframes';
  vpObj.audio_transcript = vpObj.audio_transcript || subtitle_original;
  vpObj.dialogue = vpObj.dialogue || vpObj.audio_transcript || subtitle_original;

  // beats 修正到 thisDur
  if (Array.isArray(vpObj.beats)) {
    vpObj.beats = normalizeBeatsToTotal(vpObj.beats, thisDur);
  }

  // negative/constraints 兼容：不强行改格式，但给 array 时补 must
  if (Array.isArray(vpObj.negative)) {
    const must = ["Any on-screen text","Watermarks","Blur","Distortion","Cartoon look","Background warping"];
    for (const m of must) if (!vpObj.negative.includes(m)) vpObj.negative.push(m);
  }

  vpObj.video_settings = vpObj.video_settings || {};
  vpObj.video_settings.total_duration_seconds = thisDur;
  vpObj.video_settings.aspect_ratio = vpObj.video_settings.aspect_ratio || '9:16';
  vpObj.video_settings.fps = vpObj.video_settings.fps ?? 25;
  vpObj.video_settings.look = vpObj.video_settings.look
    || 'TikTok-native smartphone video, realistic phone texture (subtle noise + mild compression), slight handheld micro-shake';

  // 最终 stringify（保证下游写库是 string）
  const video_prompt = JSON.stringify(vpObj);

  return {
    shot_no,
    subtitle_original,
    scene_context,
    video_prompt,
  };
});

return [{
  json: {
    parsed_shots_count: shots.length,
    shots,
    _debug_raw_head: raw.slice(0, 220),
    _debug_json_head: jsonText.slice(0, 220),
    video_duration_s: Number.isFinite(video_duration_s) ? Number(video_duration_s.toFixed(3)) : undefined
  }
}];

const store =
  (typeof $getWorkflowStaticData === 'function')
    ? $getWorkflowStaticData('node')
    : (typeof getWorkflowStaticData === 'function')
      ? getWorkflowStaticData('node')
      : null;

const recordId =
  String($json.record_id ?? $('提取任务字段')?.first()?.json?.record_id ?? 'unknown_record');

if (store && store[recordId]) delete store[recordId];

return [{ json: { cleared: true, record_id: recordId } }];

// 当前 item：来自“读取截图”，通常只剩文件信息 + binary
const cur = $input.item;
const j = cur.json || {};
const bin = cur.binary || {};

// 从“拆分首尾帧”取回原始帧元数据（这里一定有 shot_no / frame_type / frame_path）
const metas = $items('拆分首尾帧').map(x => x.json || {});
if (!metas.length) throw new Error('补回失败：拿不到“拆分首尾帧”的数据');

const fileName = String(j.fileName || '');
const filePath = String(j.filePath || j.path || j.frame_path || '');

const guessPath = filePath || (fileName ? `/tmp/${fileName}` : '');

const meta =
  metas.find(m => String(m.frame_path) === guessPath) ||
  metas.find(m => fileName && String(m.frame_path).endsWith(`/${fileName}`)) ||
  null;

if (!meta) {
  const sample = metas.slice(0, 3).map(m => m.frame_path).join(' | ');
  throw new Error(`补回失败：无法匹配元数据。fileName=${fileName}, filePath=${filePath}, guessPath=${guessPath}, metas_sample=${sample}`);
}

// meta 放前面，确保 shot_no/frame_type 不会被覆盖丢掉
return {
  json: {
    ...meta,
    ...j,
    frame_path: meta.frame_path || guessPath,
  },
  binary: bin,
};

const task = $('提取任务字段').first().json || {};
const recordId = task.record_id || $json.record_id || 'unknown_record';

// 从清洗结果来的 shot_no（展示用）
const shotNo = Number($json.shot_no ?? 1);
if (!Number.isFinite(shotNo) || shotNo <= 0) throw new Error(`shot_no 非法：${$json.shot_no}`);

// start_time：优先用清洗结果输出的 start_time（更稳）
let start = Number($json.start_time);
if (!Number.isFinite(start) || start < 0) {
  // 兜底：按 8s 步长推
  start = (shotNo - 1) * 8;
}

// duration：关键！最后一段会是 3s
let duration_s = Number($json.duration_s ?? 8);
if (!Number.isFinite(duration_s) || duration_s <= 0) duration_s = 8;

// 从“整理分析提示词”或“解析视频时长”取总时长（用于 clamp）
const meta = (() => { try { return $('整理分析提示词').first().json || {}; } catch(e){ return {}; }})();
const durPack = (() => { try { return $('解析视频时长').first().json || {}; } catch(e){ return {}; }})();
const video_duration_s = Number(meta.video_duration_s || durPack.video_duration_s || 0);

const video_path = `/tmp/${recordId}.mp4`;
const frame_path_start = `/tmp/${recordId}_shot${shotNo}_start.jpg`;
const frame_path_end   = `/tmp/${recordId}_shot${shotNo}_end.jpg`;

// 首帧：start + 0.2
let cap_s = start + 0.2;

// 尾帧：start + duration - 0.2（最小不小于 start+0.2）
let cap_e = start + Math.max(0.2, duration_s - 0.2);

// clamp 到视频总时长（保险，避免接近末尾抽不到）
if (Number.isFinite(video_duration_s) && video_duration_s > 0) {
  const maxT = Math.max(0, video_duration_s - 0.2);
  cap_s = Math.min(cap_s, maxT);
  cap_e = Math.min(cap_e, maxT);
  // 再保证 cap_e >= cap_s
  if (cap_e < cap_s) cap_e = cap_s;
}

cap_s = Number(cap_s.toFixed(3));
cap_e = Number(cap_e.toFixed(3));

return {
  json: {
    ...$json,

    record_id: recordId,
    shot_no: shotNo,

    video_duration_s: Number.isFinite(video_duration_s) ? Number(video_duration_s.toFixed(3)) : undefined,

    video_path,
    frame_path_start,
    frame_path_end,

    duration_s: Number(duration_s.toFixed(3)),
    cap_s,
    cap_e,
  }
};

parameters.command:
=sh -c '
IN="{{ $json.video_path }}";
S="{{ $json.frame_path_start }}";
E="{{ $json.frame_path_end }}";
CS="{{ $json.cap_s }}";
CE="{{ $json.cap_e }}";

# 1) 首帧
ffmpeg -hide_banner -loglevel error -y \
  -ss "$CS" -i "$IN" -frames:v 1 -q:v 3 "$S" || true

# 2) 尾帧
ffmpeg -hide_banner -loglevel error -y \
  -ss "$CE" -i "$IN" -frames:v 1 -q:v 3 "$E" || true

# 兜底：首帧都没有就直接报错（否则后面全是空）
[ -s "$S" ] || { echo "start frame missing"; exit 1; }

# 兜底：尾帧缺失复制首帧
[ -s "$E" ] || cp "$S" "$E"
'

parameters.jsCode:
const task = $('提取任务字段').first().json || {};
const talent_traits = task.talent_traits || '';
const product_name = task.product_name || '';
const product_selling_points = task.product_selling_points || '';

const instruction = `
You are a concise English copywriter.
Convert the inputs into concise English for image prompting.
Return ONLY JSON:
{
  "model_identity_en": "...",
  "outfit_desc_en": "..."
}
Rules:
- Each field <= 140 characters.
- Do NOT add extra keys.
`;

const gemini_body = {
  contents: [{
    role: 'user',
    parts: [{
      text: `${instruction}\n\nModel Identity (raw): ${talent_traits}\n\nOutfit/Product (raw): ${product_name}; ${product_selling_points}`
    }]
  }],
  generationConfig: { temperature: 0.2, topP: 0.9, maxOutputTokens: 512 }
};

return [{ json: { gemini_body } }];

// 清洗 + 解析 fenced JSON（兼容 ```json ... ``` 和前后杂质）
// 目标输出：model_identity_en, outfit_desc_en

const item = $input.first()?.json || {};

function toStr(v) {
  if (v == null) return '';
  if (typeof v === 'string') return v;
  try { return JSON.stringify(v); } catch (e) { return String(v); }
}

// 1) 找到最可能的文本来源：优先 output
function pickRaw(j) {
  if (typeof j.output === 'string' && j.output.trim()) return j.output;
  if (typeof j.text === 'string' && j.text.trim()) return j.text;

  // 兼容 Gemini/OpenAI 常见结构（有就取）
  const c = j?.candidates?.[0] || j?.response?.candidates?.[0];
  const parts = c?.content?.parts;
  if (Array.isArray(parts) && parts.length) {
    const t = parts.map(p => p?.text).filter(Boolean).join('\n').trim();
    if (t) return t;
  }

  return toStr(j);
}

// 2) 去掉 ```json fence + 截取 { ... } 主体
function extractJsonObjectText(raw) {
  let t = toStr(raw).trim();
  if (!t) return '';

  // 统一换行
  t = t.replace(/\r\n/g, '\n').replace(/\r/g, '\n');

  // 去掉 code fence
  t = t.replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();

  // 有些会把 JSON 放在中间：截取第一个 { 到最后一个 }
  const i = t.indexOf('{');
  const j = t.lastIndexOf('}');
  if (i >= 0 && j > i) t = t.slice(i, j + 1).trim();

  // 替换可能出现的智能引号
  t = t
    .replace(/[“”]/g, '"')
    .replace(/[‘’]/g, "'");

  // 去掉不可见字符
  t = t.replace(/\uFEFF/g, '');

  return t;
}

// 3) parse（带兜底报错片段）
function safeParse(s) {
  try {
    return JSON.parse(s);
  } catch (e) {
    // 第二次兜底：常见“末尾多逗号”
    const s2 = s.replace(/,\s*([}\]])/g, '$1');
    try {
      return JSON.parse(s2);
    } catch (e2) {
      throw new Error(
        '英文压缩 JSON parse 失败：\n' +
        '---raw_head---\n' + s.slice(0, 220) + '\n' +
        '---raw_tail---\n' + s.slice(Math.max(0, s.length - 220))
      );
    }
  }
}

const raw = pickRaw(item);
const s = extractJsonObjectText(raw);
if (!s) throw new Error('清洗后 JSON 为空：请确认上游输出在字段 output');

const obj = safeParse(s);

// 输出标准字段（容错：字段名可能不一致）
const model_identity_en =
  String(obj.model_identity_en ?? obj.model_identity ?? obj.identity ?? '').trim();

const outfit_desc_en =
  String(obj.outfit_desc_en ?? obj.outfit_description_en ?? obj.outfit_desc ?? obj.outfit ?? '').trim();

return [{
  json: {
    model_identity_en,
    outfit_desc_en,
    _raw: raw,      // 方便你调试，确认上游到底回了啥
    _json_text: s   // 清洗后的 JSON 文本
  }
}];

const raw = String($json.stdout ?? $json.data ?? '').trim();
const duration = Number(raw);
if (!Number.isFinite(duration) || duration <= 0) {
  throw new Error(`ffprobe 时长解析失败：raw=${raw}`);
}
return [{ json: { video_duration_s: duration } }];
